import{c as d,Q as e,j as r,m as l}from"./chunks/framework.rlpw0eGz.js";const h=JSON.parse('{"title":"FPV OpenIPC Thinker Air Unit","description":"OpenIPC Thinker: технічні характеристики та встановлення","frontmatter":{"title":"FPV OpenIPC Thinker Air Unit","description":"OpenIPC Thinker: технічні характеристики та встановлення","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/hardware/vtx/thinkerairunit"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/hardware/vtx/thinkerairunit"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/hardware/vtx/thinkerairunit"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/hardware/vtx/thinkerairunit"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/hardware/vtx/thinkerairunit"}],["meta",{"property":"og:title","content":"FPV OpenIPC Thinker Air Unit"}],["meta",{"property":"og:description","content":"OpenIPC Thinker: технічні характеристики та встановлення"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"name":"twitter:title","content":"FPV OpenIPC Thinker Air Unit"}],["meta",{"name":"twitter:description","content":"OpenIPC Thinker: технічні характеристики та встановлення"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Обладнання\\",\\"item\\":\\"https://openfpv.com.ua/hardware/vtx/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"FPV OpenIPC Thinker Air Unit\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"FPV OpenIPC Thinker Air Unit\\",\\"description\\":\\"OpenIPC Thinker: технічні характеристики та встановлення\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/hardware/vtx/thinkerairunit\\",\\"image\\":\\"https://openfpv.com.ua/og-hardware.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"hardware/vtx/thinkerairunit.md","filePath":"hardware/vtx/thinkerairunit.md","lastUpdated":1780228136000}'),o={name:"hardware/vtx/thinkerairunit.md"};function i(p,t,n,a,s,g){return e(),r("div",null,[...t[0]||(t[0]=[l(`<p>OpenIPC Thinker — це компактний блок камери та передачі відео, що легко інтегрується з різними RC-пристроями.</p><p>Доступні дві версії:</p><ul><li><strong>Базова</strong> (<a href="https://store.openipc.org/OpenIPC-Thinker-v1-0-Base-with-SD-p711054393" target="_blank" rel="noreferrer">Магазин</a>) — слот для SD-картки, потребує зовнішнього WiFi-модуля</li><li><strong>Tiny</strong> (<a href="https://store.openipc.org/OpenIPC-Thinker-v1-0-Tiny-with-WiFi-p633445803" target="_blank" rel="noreferrer">Магазин</a>) — інтегрований WiFi модуль RTL8731BU[^1], але без SD-картки</li></ul><blockquote><p>RTL8731BU: 50мВт @ 5G, 125мВт @ 2.4G</p></blockquote><p><img src="https://raw.githubusercontent.com/OpenIPC/docs/refs/heads/main/src/assets/images/aio-thinker/thinker-webshop-photo.jpg" alt="Набір Thinker"></p><h3 id="характеристики" tabindex="-1">Характеристики <a class="header-anchor" href="#характеристики" aria-label="Permalink to &quot;Характеристики&quot;">​</a></h3><ul><li>SoC SSC338Q</li><li>Живлення: 2–6S</li><li>Вбудований BEC на 3A</li><li>MEMS мікрофон</li><li>Інтерфейси: <ul><li>3x UART</li><li>1x MIPI для камери</li><li>1x USB для WiFi (5V/3.3V)</li><li>1x Ethernet</li><li>1x живлення</li></ul></li></ul><h3 id="фізичні-параметри" tabindex="-1">Фізичні параметри <a class="header-anchor" href="#фізичні-параметри" aria-label="Permalink to &quot;Фізичні параметри&quot;">​</a></h3><ul><li>Розмір плати: 25×25 мм</li><li>Вага: <ul><li>Без радіатора: ~8.8 г</li><li>З радіатором: ~13.4 г</li></ul></li><li>Отвори: <ul><li>PCB: 20×20 мм</li><li>З радіатором: 25.5×25.5 мм</li></ul></li><li>Охолодження: алюмінієвий радіатор</li></ul><h3 id="камери" tabindex="-1">Камери <a class="header-anchor" href="#камери" aria-label="Permalink to &quot;Камери&quot;">​</a></h3><p><strong>IMX335</strong> (<a href="https://store.openipc.org/OpenIPC-IMX335-v2-module-without-cable-p721231276" target="_blank" rel="noreferrer">Магазин</a>)</p><ul><li>14×14 мм, алюмінієвий корпус</li><li>Об&#39;єктив: 140°, f/2.8</li><li>Сенсор IMX335 з IMU</li></ul><p><strong>IMX415</strong> (<a href="https://store.openipc.org/OpenIPC-IMX415-v2-module-without-cable-p721152215" target="_blank" rel="noreferrer">Магазин</a>) — інший сенсор з тим самим залізом</p><hr><h3 id="встановлення-обладнання" tabindex="-1">Встановлення обладнання <a class="header-anchor" href="#встановлення-обладнання" aria-label="Permalink to &quot;Встановлення обладнання&quot;">​</a></h3><p>Підключення живлення та контролера польоту</p><ol><li>Знайдіть 6-жильний кабель живлення/UART (JST): чорний, чорний, жовтий, зелений, червоний, червоний</li><li>Чорні — до мінусу живлення, червоні — до плюсу</li><li>Зелений → TX, жовтий → RX (на FC)</li><li>TX до RX, RX до TX</li><li>Підключіть кабель до роз&#39;єму живлення/UART2 (сторона з радіатором)</li></ol><p>Підключення Wi-Fi модуля (лише для базової версії)</p><ol><li>Tiny версія не потребує цього кроку</li><li>Використайте USB кабель: червоний (+), синій (D-), жовтий (D+), чорний (GND)</li><li>Підключіть згідно з розкладкою: GND → GND, червоний → VCC, жовтий → D+, синій → D-</li></ol><p>Заміна камери</p><ol><li>За замовчуванням встановлено IMX335</li><li>Зніміть радіатор (4 гвинти), обережно</li><li>Від&#39;єднайте камеру та підключіть нову</li><li>Поверніть радіатор назад (не видаляйте термопрокладку!)</li></ol><p>Ethernet для конфігурації та оновлень</p><ol><li>Візьміть Ethernet кабель: 6-pin JST ↔ RJ45</li><li>Підключіть JST до Ethernet/UART0 (сторона без радіатора)</li><li>Підключіть RJ45 до ПК або маршрутизатора</li></ol><p><img src="https://raw.githubusercontent.com/OpenIPC/docs/refs/heads/main/src/assets/images/aio-thinker/thinker-connectivity.png" alt="Компоненти Thinker"></p><hr><table style="width:100%;border-collapse:collapse;margin:15px 0;"><thead><tr><th style="padding:10px;border:1px solid #ddd;">Секція</th><th style="padding:10px;border:1px solid #ddd;">Назва піна</th><th style="padding:10px;border:1px solid #ddd;">Напрямок</th><th style="padding:10px;border:1px solid #ddd;">Опис</th></tr></thead><tbody><tr><td rowspan="6" style="padding:8px;border:1px solid #ddd;"><strong>RJ45 / UART0 Header</strong></td><td style="padding:8px;border:1px solid #ddd;">UART0 RX</td><td style="padding:8px;border:1px solid #ddd;">Вхід</td><td style="padding:8px;border:1px solid #ddd;">Лінія прийому UART0</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">UART0 TX</td><td style="padding:8px;border:1px solid #ddd;">Вихід</td><td style="padding:8px;border:1px solid #ddd;">Лінія передачі UART0</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">RJ45 TX+</td><td style="padding:8px;border:1px solid #ddd;">Вихід</td><td style="padding:8px;border:1px solid #ddd;">Ethernet передача TX+</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">RJ45 TX-</td><td style="padding:8px;border:1px solid #ddd;">Вихід</td><td style="padding:8px;border:1px solid #ddd;">Ethernet передача TX-</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">RJ45 RX+</td><td style="padding:8px;border:1px solid #ddd;">Вхід</td><td style="padding:8px;border:1px solid #ddd;">Ethernet прийом RX+</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">RJ45 RX-</td><td style="padding:8px;border:1px solid #ddd;">Вхід</td><td style="padding:8px;border:1px solid #ddd;">Ethernet прийом RX-</td></tr><pre><code>&lt;tr&gt;&lt;td rowspan=&quot;4&quot; style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;&lt;strong&gt;USB Header&lt;/strong&gt;&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Vd&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вихід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Живлення для зовнішнього Wi-Fi модуля&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;DM&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід/Вихід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;USB Data− (D−)&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;DP&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід/Вихід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;USB Data+ (D+)&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;GND&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;—&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Земля&lt;/td&gt;&lt;/tr&gt;

&lt;tr&gt;&lt;td rowspan=&quot;6&quot; style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;&lt;strong&gt;Power / UART2 Header&lt;/strong&gt;&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Vcc&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід живлення&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Vcc (дубль)&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Дублюючий пін живлення (об&#39;єднується)&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;RX&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;UART2 прийом (до контролера польоту)&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;TX&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вихід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;UART2 передача (до контролера польоту)&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;GND&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;—&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Земля&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;GND (дубль)&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;—&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Дублюючий пін землі (об&#39;єднується)&lt;/td&gt;&lt;/tr&gt;

&lt;tr&gt;&lt;td rowspan=&quot;2&quot; style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;&lt;strong&gt;UART1 (контакти для пайки)&lt;/strong&gt;&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;RX&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вхід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;UART1 прийом&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;TX&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;Вихід&lt;/td&gt;&lt;td style=&quot;padding: 8px; border: 1px solid #ddd;&quot;&gt;UART1 передача&lt;/td&gt;&lt;/tr&gt;
</code></pre></tbody></table> ---- ::: info Поради ::: <pre><code>- Не подавайте живлення через USB Vd.  
- Не знімайте термопрокладку з радіатора.  
- Для Wi-Fi на 3.3V — зніміть резистор вибору напруги.  
- Модулі з високим споживанням можна живити окремо.
</code></pre><hr><h3 id="налаштування-програмного-забезпечення" tabindex="-1">Налаштування програмного забезпечення <a class="header-anchor" href="#налаштування-програмного-забезпечення" aria-label="Permalink to &quot;Налаштування програмного забезпечення&quot;">​</a></h3><p><strong>Доступ до Web UI</strong></p><ul><li>DHCP: підключіть до мережі, знайдіть IP на роутері</li><li>Статична IP: 192.168.1.10 (вручну налаштуйте інтерфейс ПК)</li></ul><blockquote><p>Логін за замовчуванням:</p><ul><li>Користувач: <code>root</code></li><li>Пароль: <code>12345</code></li></ul></blockquote><h3 id="оновлення-прошивки" tabindex="-1">Оновлення прошивки <a class="header-anchor" href="#оновлення-прошивки" aria-label="Permalink to &quot;Оновлення прошивки&quot;">​</a></h3><ul><li>Через Web UI (потрібен інтернет)</li><li>Через <a href="https://github.com/OpenIPC/openipc-configurator" target="_blank" rel="noreferrer">OpenIPC Configurator</a></li></ul><p><strong>Прошивки:</strong></p><ul><li><a href="https://github.com/OpenIPC/builder/releases/download/latest/ssc338q_fpv_openipc-thinker-aio-nor.tgz" target="_blank" rel="noreferrer">Стандартна</a></li><li><a href="https://github.com/OpenIPC/builder/releases/download/latest/ssc338q_fpv_openipc-urllc-aio-nor.tgz" target="_blank" rel="noreferrer">Для RTL8812EU</a></li></ul><p><strong>Додатково</strong></p><p>Використовуйте <a href="https://github.com/OpenIPC/openipc-configurator" target="_blank" rel="noreferrer">OpenIPC Configurator</a></p>`,39)])])}const x=d(o,[["render",i]]);export{h as __pageData,x as default};
